import './TabsScroller.scss';

import { IconButton } from ':components/IconButton';
import { classNames } from ':helpers/classnames';
import { getBEMClasses } from ':helpers/get-bem';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import React, { useEffect, useRef, useState } from 'react';

import type { TabsScrollerProps } from './TabsScroller.types';

const [scrollerClassName, , scrollerElement] = getBEMClasses('dsb_tabs-scroller');
const [scrollerContentClassName, scrollerContentModifier] = scrollerElement('content');
const [navButton, navButtonModifier] = scrollerElement('nav-button');

export const TabsScroller: React.FC<TabsScrollerProps> = ({ className, children, onScroll }) => {
	const containerRef = useRef<HTMLDivElement>(null);
	const contentRef = useRef<HTMLDivElement>(null);
	const [scrollEnabled, setScrolling] = useState(false);
	const [scrollLeftAllowed, allowLeftScrolling] = useState(false);
	const [scrollRightAllowed, allowRightScrolling] = useState(false);

	useEffect(() => {
		const resizeHandler = (): void => {
			const containerElement = containerRef?.current;
			const contentElement = contentRef?.current;

			if (!containerElement || !contentElement) {
				return;
			}

			const containerWidth = containerElement.getBoundingClientRect().width;
			const contentWidth = contentElement.scrollWidth;

			const needScroll = contentWidth > containerWidth;

			if (needScroll && !scrollEnabled) {
				setScrolling(true);
			} else if (!needScroll && scrollEnabled) {
				setScrolling(false);
			}
		};

		const scrollHandler = (): void => {
			const containerElement = containerRef?.current;
			const contentElement = contentRef?.current;

			if (!containerElement || !contentElement) {
				return;
			}

			const containerWidth = containerElement.getBoundingClientRect().width;
			const contentWidth = contentElement.scrollWidth;
			const contentScrollLeft = contentElement.scrollLeft;

			const scrollOnStart = contentScrollLeft === 0;
			const scrollOnEnd = Math.round(contentScrollLeft + containerWidth) >= contentWidth;

			allowRightScrolling(!scrollOnEnd && scrollEnabled);
			allowLeftScrolling(!scrollOnStart && scrollEnabled);

			onScroll({
				scrollLeft: contentElement.scrollLeft,
				scrollTop: contentElement.scrollTop,
			});
		};

		resizeHandler();
		scrollHandler();

		window.addEventListener('resize', resizeHandler);
		contentRef.current?.addEventListener('scroll', scrollHandler);

		return (): void => {
			window.removeEventListener('resize', resizeHandler);
			contentRef.current?.removeEventListener('scroll', scrollHandler);
		};
	}, [scrollEnabled, scrollLeftAllowed, scrollRightAllowed, onScroll]);

	const scrollClassName = classNames(scrollerContentClassName, {
		[scrollerContentModifier('enable')]: scrollEnabled,
	});

	const onRightScrollClick = (): void => {
		const contentElement = contentRef?.current;
		if (!contentElement) {
			return;
		}

		contentElement.scrollLeft = contentElement.scrollLeft + 100;

		onScroll({
			scrollLeft: contentElement.scrollLeft,
			scrollTop: contentElement.scrollTop,
		});
	};

	const onLeftScrollClick = (): void => {
		const contentElement = contentRef?.current;

		if (!contentElement) {
			return;
		}

		contentElement.scrollLeft = contentElement.scrollLeft - 100;

		onScroll({
			scrollLeft: contentElement.scrollLeft,
			scrollTop: contentElement.scrollTop,
		});
	};

	return (
		<div data-testid="TabsScroller" className={classNames(scrollerClassName, className)} ref={containerRef}>
			<div className={scrollClassName} ref={contentRef}>
				{children}
			</div>
			{scrollEnabled && (
				<>
					{scrollLeftAllowed && (
						<IconButton
							className={classNames(navButton, navButtonModifier('left-arrow'))}
							iconName={Icons.NavArrowLeft}
							onClick={onLeftScrollClick}
							size="large"
						/>
					)}
					{scrollRightAllowed && (
						<IconButton
							className={classNames(navButton, navButtonModifier('right-arrow'))}
							iconName={Icons.NavArrowRight}
							onClick={onRightScrollClick}
							size="large"
						/>
					)}
				</>
			)}
		</div>
	);
};
